using System.Collections;
using TMPro;
using UnityEngine;
using UnityEngine.InputSystem;
using UnityEngine.UI;

/// <summary>
/// Renderizador de mensagens de tutorial — gerido por
/// <see cref="TutorialMessageManager"/>. Trata dos três tipos de painel:
///
/// <list type="bullet">
///   <item><b>Importante</b> (<see cref="importantRoot"/>): centro do ecrã,
///     suporta imagem (<see cref="importantImage"/>), texto longo rola (
///     <see cref="importantScrollRect"/>) ao pressionar "Continuar", confirmar
///     via botão ou input. Pausa o jogo durante a exibição.</item>
///   <item><b>Média</b> (<see cref="mediaRoot"/>): posicionamento configurável
///     via <see cref="TutorialMessageRequest.anchorPosition"/>, requer
///     confirmação, sem imagem.</item>
///   <item><b>Toast / Não Importante</b> (<see cref="toastRoot"/>): pop-up no
///     topo, fade in/out, sem confirmação.</item>
/// </list>
///
/// <b>Scroll de texto longo (Importante):</b>
/// Se o texto não cabe numa "página", o botão "Continuar" avança para a
/// próxima página até chegar ao fim, quando então fecha o painel. Isto evita
/// caixas de diálogo enormes e mantém a leitura confortável.
///
/// <b>Montagem no Editor:</b>
/// - <see cref="importantRoot"/>: painel central (CanvasGroup + RectTransform).
/// - <see cref="importantCanvasGroup"/>: para fade in/out.
/// - <see cref="importantImageContainer"/>: GameObject pai da imagem —
///   desactivado quando <see cref="TutorialMessageRequest.image"/> é null.
/// - <see cref="importantImage"/>: a Image que exibe o sprite.
/// - <see cref="importantScrollRect"/>: ScrollRect com o texto (scroll vertical).
/// - <see cref="importantText"/>: TMP_Text dentro do ScrollRect.
/// - <see cref="importantConfirmButton"/>: botão "Continuar"/"Fechar".
/// - <see cref="importantConfirmLabel"/>: TMP_Text do botão ("Continuar" / "Fechar").
/// - <see cref="mediaRoot"/> / <see cref="mediaText"/> / <see cref="mediaConfirmButton"/>:
///   mesmo padrão, sem imagem; <see cref="mediaRectTransform"/> posicionado em
///   runtime via anchorPosition.
/// - <see cref="toastRoot"/> / <see cref="toastText"/> / <see cref="toastCanvasGroup"/>:
///   painel pequeno no topo do Canvas — sem confirmação.
/// </summary>
[RequireComponent(typeof(Canvas))]
public class TutorialMessageUI : MonoBehaviour
{
    // ==================== Importante ====================

    [Header("Painel Importante (centro do ecrã)")]
    [SerializeField] private GameObject      importantRoot;
    [SerializeField] private CanvasGroup     importantCanvasGroup;
    [SerializeField] private GameObject      importantImageContainer;
    [SerializeField] private Image           importantImage;
    [SerializeField] private ScrollRect      importantScrollRect;
    [SerializeField] private TMP_Text        importantText;
    [SerializeField] private Button          importantConfirmButton;
    [SerializeField] private TMP_Text        importantConfirmLabel;
    [SerializeField] private string          continueLabel = "Continuar";
    [SerializeField] private string          closeLabel    = "Fechar";

    // ==================== Média ====================

    [Header("Painel Média (perto de elemento da HUD)")]
    [SerializeField] private GameObject      mediaRoot;
    [SerializeField] private CanvasGroup     mediaCanvasGroup;
    [SerializeField] private TMP_Text        mediaText;
    [SerializeField] private Button          mediaConfirmButton;
    [SerializeField] private RectTransform   mediaRectTransform;

    // ==================== Toast / Não Importante ====================

    [Header("Toast (Não Importante — topo do ecrã)")]
    [SerializeField] private GameObject      toastRoot;
    [SerializeField] private CanvasGroup     toastCanvasGroup;
    [SerializeField] private TMP_Text        toastText;

    [Header("Transição")]
    [Tooltip("Duração do fade in/out de todos os painéis, em segundos.")]
    [SerializeField] private float fadeDuration = 0.2f;

    // ==================== Estado ====================

    private bool _confirmPressed;
    private bool _toastRunning;

    private void Awake()
    {
        if (importantRoot  != null) importantRoot.SetActive(false);
        if (mediaRoot      != null) mediaRoot.SetActive(false);
        if (toastRoot      != null) toastRoot.SetActive(false);

        if (importantConfirmButton != null)
            importantConfirmButton.onClick.AddListener(OnConfirmPressed);
        if (mediaConfirmButton != null)
            mediaConfirmButton.onClick.AddListener(OnConfirmPressed);
    }

    // ==================== Corrotinas Públicas ====================

    /// <summary>
    /// Mostra o painel correcto para "request" e aguarda até o jogador confirmar.
    /// Chama "onConfirmed" ao fechar. Chamado por TutorialMessageManager.
    /// </summary>
    public IEnumerator ShowConfirmRoutine(TutorialMessageRequest request, System.Action onConfirmed)
    {
        if (request.type == TutorialMessageType.Importante)
            yield return ShowImportantRoutine(request, onConfirmed);
        else
            yield return ShowMediaRoutine(request, onConfirmed);
    }

    /// <summary>
    /// Exibe um toast no topo do ecrã durante "duration" segundos, com fade.
    /// Chamado por TutorialMessageManager para mensagens NaoImportante.
    /// </summary>
    public IEnumerator ShowToastRoutine(string text, float duration)
    {
        if (toastRoot == null || toastCanvasGroup == null) yield break;

        if (toastText != null) toastText.text = text;

        toastRoot.SetActive(true);
        yield return FadeRoutine(toastCanvasGroup, 0f, 1f);
        yield return WaitUnscaled(duration);
        yield return FadeRoutine(toastCanvasGroup, 1f, 0f);
        toastRoot.SetActive(false);
    }

    // ==================== Importante ====================

    private IEnumerator ShowImportantRoutine(TutorialMessageRequest request, System.Action onConfirmed)
    {
        if (importantRoot == null) { onConfirmed?.Invoke(); yield break; }

        // Configura imagem.
        bool hasImage = request.image != null;
        if (importantImageContainer != null) importantImageContainer.SetActive(hasImage);
        if (importantImage != null)
        {
            importantImage.sprite  = request.image;
            importantImage.enabled = hasImage;
        }

        // Configura texto e scroll.
        if (importantText != null) importantText.text = request.text ?? "";

        // Reset scroll para o topo.
        if (importantScrollRect != null)
        {
            Canvas.ForceUpdateCanvases();
            importantScrollRect.verticalNormalizedPosition = 1f;
        }

        UpdateConfirmLabel();

        importantRoot.SetActive(true);
        if (importantCanvasGroup != null) yield return FadeRoutine(importantCanvasGroup, 0f, 1f);

        GamePauseUtil.Pause();

        _confirmPressed = false;

        while (true)
        {
            // Input: gamepad Sul (A/Cross) ou teclado Enter/Space.
            if (PollConfirmInput() || _confirmPressed)
            {
                _confirmPressed = false;

                // Se o texto ainda tem conteúdo abaixo: avança uma "página".
                if (importantScrollRect != null && !IsScrolledToBottom())
                {
                    ScrollPage();
                    UpdateConfirmLabel();
                }
                else
                {
                    break; // Fecha.
                }
            }

            yield return null;
        }

        if (importantCanvasGroup != null) yield return FadeRoutine(importantCanvasGroup, 1f, 0f);
        importantRoot.SetActive(false);

        GamePauseUtil.Resume();
        onConfirmed?.Invoke();
    }

    // ==================== Média ====================

    private IEnumerator ShowMediaRoutine(TutorialMessageRequest request, System.Action onConfirmed)
    {
        if (mediaRoot == null) { onConfirmed?.Invoke(); yield break; }

        if (mediaText != null) mediaText.text = request.text ?? "";

        // Posicionamento: anchorPosition em coordenadas de viewport/canvas.
        if (mediaRectTransform != null && request.anchorPosition != default)
            mediaRectTransform.anchoredPosition = request.anchorPosition;

        mediaRoot.SetActive(true);
        if (mediaCanvasGroup != null) yield return FadeRoutine(mediaCanvasGroup, 0f, 1f);

        GamePauseUtil.Pause();

        _confirmPressed = false;

        while (true)
        {
            if (PollConfirmInput() || _confirmPressed)
            {
                _confirmPressed = false;
                break;
            }
            yield return null;
        }

        if (mediaCanvasGroup != null) yield return FadeRoutine(mediaCanvasGroup, 1f, 0f);
        mediaRoot.SetActive(false);

        GamePauseUtil.Resume();
        onConfirmed?.Invoke();
    }

    // ==================== Helpers ====================

    private void OnConfirmPressed() => _confirmPressed = true;

    private bool PollConfirmInput()
    {
        var keyboard = Keyboard.current;
        if (keyboard != null && (keyboard.enterKey.wasPressedThisFrame || keyboard.spaceKey.wasPressedThisFrame))
            return true;

        var gamepad = Gamepad.current;
        if (gamepad != null && gamepad.buttonSouth.wasPressedThisFrame)
            return true;

        return false;
    }

    private bool IsScrolledToBottom()
    {
        if (importantScrollRect == null) return true;

        // Considera "no fundo" quando o scroll está a ≤ 5% do fim.
        return importantScrollRect.verticalNormalizedPosition <= 0.05f;
    }

    private void ScrollPage()
    {
        if (importantScrollRect == null) return;

        // Avança uma "página" (altura do viewport).
        float viewportHeight = importantScrollRect.viewport != null
            ? importantScrollRect.viewport.rect.height
            : 200f;

        float contentHeight = importantScrollRect.content != null
            ? importantScrollRect.content.rect.height
            : viewportHeight;

        float scrollableHeight = Mathf.Max(0f, contentHeight - viewportHeight);
        if (scrollableHeight <= 0f) return;

        // Quanto o scroll atual está em pixels do topo.
        float currentPixelOffset = (1f - importantScrollRect.verticalNormalizedPosition) * scrollableHeight;
        float nextPixelOffset    = Mathf.Min(currentPixelOffset + viewportHeight, scrollableHeight);

        importantScrollRect.verticalNormalizedPosition = 1f - nextPixelOffset / scrollableHeight;
    }

    private void UpdateConfirmLabel()
    {
        if (importantConfirmLabel == null) return;

        bool atBottom = importantScrollRect == null || IsScrolledToBottom();
        importantConfirmLabel.text = atBottom ? closeLabel : continueLabel;
    }

    private IEnumerator FadeRoutine(CanvasGroup group, float from, float to)
    {
        if (group == null) yield break;

        group.alpha = from;
        if (fadeDuration <= 0f) { group.alpha = to; yield break; }

        float t = 0f;
        while (t < fadeDuration)
        {
            t          += Time.unscaledDeltaTime;
            group.alpha = Mathf.Lerp(from, to, t / fadeDuration);
            yield return null;
        }
        group.alpha = to;
    }

    private IEnumerator WaitUnscaled(float duration)
    {
        float t = 0f;
        while (t < duration) { t += Time.unscaledDeltaTime; yield return null; }
    }
}
